// ── Formatting helpers ──────────────────────────────────────────────────────
function pct(v, dec = 1) {
  if (v == null || isNaN(v)) return "—"
  const s = (v * 100).toFixed(dec) + "%"
  return v &gt;= 0 ? "+" + s : s
}
function num(v, dec = 2) { return (v == null || isNaN(v)) ? "—" : v.toFixed(dec) }
function pos(v) { return (v == null || isNaN(v)) ? "#888" : v &gt;= 0 ? "#6fcfa0" : "#e07070" }
function neg(v) { return (v == null || isNaN(v)) ? "#888" : v &lt;= 0 ? "#6fcfa0" : "#e07070" }

