function bestBy(metric, higher_is_better = true) {
  const valid = summary_df.filter(d =&gt; d[metric] != null && !isNaN(d[metric]))
  if (!valid.length) return null
  return valid.reduce((a, b) =&gt;
    higher_is_better ? (b[metric] &gt; a[metric] ? b : a)
                     : (b[metric] &lt; a[metric] ? b : a)
  )
}

