set.seed(7)

metros &lt;- c("Johannesburg", "Cape Town", "Durban", "Pretoria")
quarters &lt;- seq(as.Date("2015-01-01"), as.Date("2024-10-01"), by = "quarter")

# Simulate price index (base = 100 at start) with different growth paths
df &lt;- expand_grid(metro = metros, date = quarters) |&gt;
  arrange(metro, date) |&gt;
  group_by(metro) |&gt;
  mutate(
    base_growth = case_when(
      metro == "Cape Town"     ~ 0.025,
      metro == "Johannesburg"  ~ 0.015,
      metro == "Pretoria"      ~ 0.018,
      metro == "Durban"        ~ 0.010
    ),
    noise       = cumsum(rnorm(n(), 0, 0.8)),
    index       = 100 * cumprod(1 + base_growth / 4 + rnorm(n(), 0, 0.005))
  ) |&gt;
  ungroup()
